function httpGetText(urlString) {
  return new Promise((resolve, reject) => {
    const req = http.get(urlString, (res) => {
      let body = '';
      res.on('data', (chunk) => { body += chunk; });
      res.on('end', () => {
        resolve(body);
      });
    });
    req.on('error', reject);
    req.setTimeout(3000, () => { req.destroy(); reject(new Error('HTTP timeout')); });
  });
